    planungstyp               number(8, 0),
    planungstypbeschreibung   varchar2(50 char),
    termin                    varchar2(19 char),
    status                    number(8, 0),
    statusbeschreibung        varchar2(50 char),
    gesperrt                  number(8, 0),
    freigegeben               number(8, 0),
    planterminfix             number(8, 0),
    planfiltertyp             number(8, 0),
    planfiltertypbeschreibung varchar2(50 char),
    planstatus                number(8, 0),
    planstatusbeschreibung    varchar2(50 char),
    planstart                 varchar2(19 char),
    planende                  varchar2(19 char),
    wert                      number(8, 0),
    prioritaetsnr             varchar2(50 char),
    prioritaetsbezeichnung    varchar2(50 char),
    prioritaetsinfo1          varchar2(50 char),
    prioritaetsinfo2          varchar2(50 char),
    prioritaetsinfo3          varchar2(50 char),
    materialnr                varchar2(50 char),
    materialbezeichnung       varchar2(50 char),
    materialinfo1             varchar2(50 char),
    materialinfo2             varchar2(50 char),
    materialinfo3             varchar2(50 char),
    arbeitsplannr             varchar2(50 char),
    arbeitsplanbezeichnung    varchar2(50 char),
    arbeitsplaninfo1          varchar2(50 char),
    arbeitsplaninfo2          varchar2(50 char),
    arbeitsplaninfo3          varchar2(50 char),
    stuecklistennr            varchar2(50 char),
    stuecklistenbezeichnung   varchar2(50 char),
    stuecklisteninfo1         varchar2(50 char),
    stuecklisteninfo2         varchar2(50 char),
    stuecklisteninfo3         varchar2(50 char),
    mengenetto                number(*, 3),
    mengebrutto               number(*, 3),
    einheitsnr                varchar2(50 char),
    einheitsbezeichnung       varchar2(50 char),
    planfruehesterstart       varchar2(19 char),
    planspaetesterstart       varchar2(19 char),
    planfruehestesende        varchar2(19 char),
    planspaetestesende        varchar2(19 char),
    fakopfname                varchar2(50 char)
